import React from 'react';
import {RouteComponentProps, withRouter} from 'react-router';

interface IPageNotFoundState {

}

interface IPageNotFoundProps extends RouteComponentProps {
    history: any;
}

class PageNotFound extends React.Component<IPageNotFoundProps, IPageNotFoundState> {

	private canvas: HTMLCanvasElement|null;
	private context2d: any;
	private fontSize: number;
	private listText: string[];
	private listColumn: number[];
	private column: number;
	private row: number;
	private drawTimer: any;
	private text1: string;
	private text2: string;
	private text3: string;

    constructor(props: IPageNotFoundProps) {
        super(props);
        this.canvas = null;
        this.fontSize = 12;
        this.column = 0;
        this.row = 0;
        this.listColumn = [];
        this.text1 = '温馨提醒';
        this.text2 = '此页面已被外星人劫持';
        this.text3 = '请点击任意处返回';
        this.listText = "abcdefghijklmnopqrstuvwxyz        ".split("");
        this.onResize = this.onResize.bind(this);
        this.onMousedown = this.onMousedown.bind(this);
        this.draw = this.draw.bind(this);
    }

    componentDidMount() {
		if (this.canvas) {
			this.context2d = this.canvas.getContext('2d');
			this.canvas.addEventListener("mousedown", this.onMousedown);
			window.addEventListener("resize", this.onResize);
			this.onResize();
			this.drawTimer = setInterval(this.draw, 40);
		}
    }

	onResize() {
        if (this.canvas) {
            this.canvas.width = window.innerWidth - 3;
            this.canvas.height = window.innerHeight - 3;
            this.column = this.canvas.width / this.fontSize;
            this.row = this.canvas.height / this.fontSize;
            for (let i = 0; i < this.column; i++) {
                this.listColumn[i] = 1;
            }
        }
	}

	onMousedown() {
        window.removeEventListener("resize", this.onResize);
        if (this.canvas) {
            this.canvas.removeEventListener("mousedown", this.onMousedown);
        }
		this.props.history.goBack();
	}

	draw() {
    	if (!this.canvas) {
    		return;
	    }
    	let cw = this.canvas.width;
    	let ch = this.canvas.height;

		this.context2d.fillStyle = "rgba(0, 0, 0, 0.05)";
		this.context2d.fillRect(0, 0, cw, ch);
		this.context2d.save();

		//画Logo
		this.context2d.shadowColor = "#133061";
		this.context2d.shadowBlur = Math.random() * 40 + 1;
		this.context2d.font = "bold 36px Arial";
		this.context2d.fillStyle = "#1890ff";
		this.context2d.fillText(this.text1, (cw / 2 - this.context2d.measureText(this.text1).width / 2), ch / 2);
		this.context2d.fillText(this.text2, (cw / 2 - this.context2d.measureText(this.text2).width / 2), ch / 2 + 50);
		this.context2d.font = "16px Microsoft Yahei";
		this.context2d.fillText(this.text3, (cw / 2 - this.context2d.measureText(this.text3).width / 2), ch / 2 + 100);

		//画代码
		this.context2d.restore();
		this.context2d.font = "normal " + this.fontSize + "px Arial";
		this.context2d.fillStyle = "#1890ff";
		for (var i = 0; i < this.column; i++) {
			if (Math.random() > 0.5) {
				var str = this.listText[Math.floor(Math.random() * this.listText.length)];
				this.context2d.fillText(str, i * this.fontSize, this.listColumn[i] * this.fontSize);
				this.listColumn[i] += 1;
				if (this.listColumn[i] >= this.row) {
					this.listColumn[i] = 0;
				}
			}
		}
	}

    render() {
        let win: any = window;
        return (
            <div 
                id="notFound"
                onContextMenu={() => {
                    win.event.returnValue = false;
                }}
                onDragStart={() => {
                    win.event.returnValue = false;
                }}>
	            <canvas ref={(canvas) => this.canvas = canvas}></canvas>
            </div>
        );
    }
}

export default withRouter(PageNotFound);
